function printLength(strOrNull: string | null) {
  if (strOrNull === null) {
    console.log("The string is null");
  } else {
    // Here we know that strOrNull is a string, so we can use a type assertion
    console.log(`The string has length ${strOrNull.length}` as string);
  }
}
```

